    private void handleIntent(@Nullable Intent intent) {
        textView.setText("");
        imagesContainer.removeAllViews();

        if (intent == null) {
            textView.setText("No intent received.");
            return;
        }

        String action = intent.getAction();
        String type = intent.getType();

        StringBuilder sb = new StringBuilder();
        sb.append("Action: ").append(action).append("\n");
        sb.append("Type: ").append(type).append("\n\n");

        Set<String> texts = new LinkedHashSet<>();
        Set<Uri> uris = new LinkedHashSet<>();

        extractFromExtras(intent, texts, uris);
        extractFromClipData(intent, texts, uris);

        String combinedText = joinTexts(texts);

        if (!combinedText.isEmpty()) {
            sb.append("Text:\n").append(combinedText).append("\n\n");
        }

        if (!uris.isEmpty()) {
            sb.append("URIs:\n");
            for (Uri u : uris) {
                sb.append(u.toString()).append("\n");
            }
        } else if (combinedText.isEmpty()) {
            sb.append("No shared content found.");
        }

        textView.setText(sb.toString());

        for (Uri uri : uris) {
            addImage(uri);
        }
    }

    private void extractFromExtras(Intent intent, Set<String> texts, Set<Uri> uris) {
        String extraText = intent.getStringExtra(Intent.EXTRA_TEXT);
        CharSequence extraCs = intent.getCharSequenceExtra(Intent.EXTRA_TEXT);
        String extraSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT);

        if (extraSubject != null && !extraSubject.trim().isEmpty()) texts.add(extraSubject.trim());
        if (extraText != null && !extraText.trim().isEmpty()) texts.add(extraText.trim());
        if (extraCs != null && extraText == null) {
            String s = extraCs.toString();
            if (!s.trim().isEmpty()) texts.add(s.trim());
        }

        Uri singleStream = intent.getParcelableExtra(Intent.EXTRA_STREAM);
        if (singleStream != null) uris.add(singleStream);

        ArrayList<Uri> multipleStreams = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
        if (multipleStreams != null) uris.addAll(multipleStreams);

        String extraHtmlText = intent.getStringExtra(Intent.EXTRA_HTML_TEXT);
        if (extraHtmlText != null && !extraHtmlText.trim().isEmpty()) {
            String url = firstUrl(extraHtmlText);
            if (url != null) texts.add(url);
        }
    }

    private void extractFromClipData(Intent intent, Set<String> texts, Set<Uri> uris) {
        ClipData clipData = intent.getClipData();
        if (clipData == null) return;

        for (int i = 0; i < clipData.getItemCount(); i++) {
            ClipData.Item item = clipData.getItemAt(i);
            if (item == null) continue;

            CharSequence t = item.getText();
            if (t != null) {
                String s = t.toString().trim();
                if (!s.isEmpty()) texts.add(s);
            }

            Uri u = item.getUri();
            if (u != null) uris.add(u);

            Intent inner = item.getIntent();
            if (inner != null) {
                String s = inner.getStringExtra(Intent.EXTRA_TEXT);
                if (s != null && !s.trim().isEmpty()) texts.add(s.trim());
                Uri su = inner.getParcelableExtra(Intent.EXTRA_STREAM);
                if (su != null) uris.add(su);
            }
        }
    }

    private void addImage(Uri uri) {
        ImageView iv = new ImageView(this);
        iv.setAdjustViewBounds(true);
        iv.setScaleType(ImageView.ScaleType.CENTER_CROP);
        int top = (int) (12 * getResources().getDisplayMetrics().density);

        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
        );
        lp.topMargin = top;

        iv.setLayoutParams(lp);

        try {
            iv.setImageURI(uri);
        } catch (Throwable ignored) {
        }

        imagesContainer.addView(iv);
    }

    private String joinTexts(Set<String> texts) {
        if (texts == null || texts.isEmpty()) return "";
        StringBuilder sb = new StringBuilder();
        boolean first = true;
        for (String t : texts) {
            if (t == null) continue;
            String s = t.trim();
            if (s.isEmpty()) continue;
            if (!first) sb.append("\n\n");
            sb.append(s);
            first = false;
        }
        return sb.toString();
    }

    private String firstUrl(String s) {
        if (s == null) return null;
        java.util.regex.Matcher m = Patterns.WEB_URL.matcher(s);
        if (m.find()) return m.group();
        return null;
    }
